+fn extract_supported_zones_from_toml(zones: Option<&toml::Value>) -> Vec<String> {
+    let Some(zones) = zones.and_then(toml::Value::as_table) else {
+        return Vec::new();
+    };
+
+    let home = zones
+        .get("home")
+        .and_then(toml::Value::as_str)
+        .map(str::to_owned);
+    let allowed_sources = zones
+        .get("allowed_sources")
+        .and_then(toml::Value::as_array)
+        .map(|values| {
+            values
+                .iter()
+                .filter_map(toml::Value::as_str)
+                .map(str::to_owned)
+                .collect::<Vec<_>>()
+        })
+        .unwrap_or_default();
+    let allowed_targets = zones
+        .get("allowed_targets")
+        .and_then(toml::Value::as_array)
+        .map(|values| {
+            values
+                .iter()
+                .filter_map(toml::Value::as_str)
+                .map(str::to_owned)
+                .collect::<Vec<_>>()
+        })
+        .unwrap_or_default();
+
+    allowed_sources
+        .into_iter()
+        .chain(allowed_targets)
+        .chain(home)
+        .collect::<BTreeSet<_>>()
+        .into_iter()
+        .collect()
+}
